#ifndef MQTT_CLIENT_H
#define MQTT_CLIENT_H
#include <PubSubClient.h>
void mqtt_setup(const char* server, uint16_t port);
void mqtt_loop();
bool mqtt_publish(const char* topic, const char* payload);
void mqtt_subscribe(const char* topic);
typedef void (*mqtt_cb)(const char* topic, const char* payload);
void mqtt_on_message(mqtt_cb cb);
bool mqtt_connected();
#endif

firmware_template.source:
#include "mqtt_client.h"
#include <WiFi.h>
static WiFiClient _wifiClient;
static PubSubClient _mqtt(_wifiClient);
static mqtt_cb _userCb = nullptr;
static const char* _server = "";
static uint16_t _port = 1883;
void _mqtt_callback(char* topic, byte* payload, unsigned int len) {
  char buf[256];
  unsigned int n = (len < 255) ? len : 255;
  memcpy(buf, payload, n); buf[n] = 0;
  if (_userCb) _userCb(topic, buf);
}
void mqtt_setup(const char* server, uint16_t port) {
  _server = server; _port = port;
  _mqtt.setServer(server, port);
  _mqtt.setCallback(_mqtt_callback);
  Serial.printf("[mqtt] Server %s:%d\n", server, port);
}
void mqtt_loop() {
  if (!_mqtt.connected()) {
    if (_mqtt.connect("parakram-device")) {
      Serial.println("[mqtt] Connected");
    }
  }
  _mqtt.loop();
}
bool mqtt_publish(const char* t, const char* p) { return _mqtt.publish(t, p); }
void mqtt_subscribe(const char* t) { _mqtt.subscribe(t); }
void mqtt_on_message(mqtt_cb cb) { _userCb = cb; }
bool mqtt_connected() { return _mqtt.connected(); }
